/**
 * Collections Page
 * 
 * Manages invoice collections and payment tracking. Displays list of invoices
 * with status indicators, supports search functionality, and provides pagination
 * for navigating through invoice records. Uses reports API to fetch collection transactions.
 */

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { FaArrowDown } from 'react-icons/fa';
import '/styles/index.css';
import { Pagination, MetricCard, LoadingSpinner } from '@/shared/components';
import { AddMoneyToWalletModal } from '@/features/wallet/components';
import GenerateCheckoutLinkModal from '@/features/checkout/components/GenerateCheckoutLinkModal.jsx';

import { useSearch } from '@/app/providers/SearchContext.jsx';
import { withAlpha } from '@/shared/utils/color-utils.js';
import { formatCurrencyAmount } from '@/shared/utils/formatAmount.js';
import reportService from '@/features/reports/services/reportService.js';
import { useQuery } from '@/shared/hooks';
import { logger } from '@/shared/utils/logger.js';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { tokenService } from '@/features/auth/services';


const parseAmount = (value) => {
  if (value === undefined || value === null || value === '') { return 0; }
  const num = Number(value);
  return Number.isNaN(num) ? 0 : num;
};

const Collections = () => {
  const { t } = useTranslation();
  const [currentPage, setCurrentPage] = useState(1);
  const [showAddMoneyModal, setShowAddMoneyModal] = useState(false);
  const [showGenerateCheckoutModal, setShowGenerateCheckoutModal] = useState(false);

  const [itemsPerPage] = useState(20);
  const [isPageLoading, setIsPageLoading] = useState(false);
  const [error, setError] = useState(null);
  const [statusFilter, setStatusFilter] = useState('all');
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const navigate = useNavigate();
  const { searchTerm, debouncedSearchTerm, updateSearch } = useSearch();

  // Detect if logged-in user is an Agent to hide checkout-related UI
  const _agentUserData = tokenService.getUserData();
  const isAgent = _agentUserData?.business?.category === 'Agent' ||
    _agentUserData?.businesses?.[0]?.category === 'Agent' ||
    _agentUserData?.category === 'Agent' ||
    _agentUserData?.business_type === 'agent' ||
    _agentUserData?.business?.business_type === 'agent' ||
    _agentUserData?.businesses?.[0]?.business_type === 'agent' ||
    _agentUserData?.industry === 'Agent';

  // Date range — default last 90 days
  const toDateInputValue = (date) => {
    const tzOffset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - tzOffset).toISOString().slice(0, 10);
  };

  const [dateRange] = useState(() => {
    const today = new Date();
    const threeMonthsAgo = new Date(today);
    threeMonthsAgo.setMonth(today.getMonth() - 3);
    return {
      startDate: toDateInputValue(threeMonthsAgo),
      endDate: toDateInputValue(today),
    };
  });

  // Fetch collections from dedicated endpoint
  const { data: reportData, isLoading, error: loadError } = useQuery({
    queryKey: queryKeys.reports.list({
      startDate: dateRange.startDate,
      endDate: dateRange.endDate,
      type: 'collections',
    }),
    endpoint: `/auth/get-collections?start_date=${dateRange.startDate}&end_date=${dateRange.endDate}`,
    staleTime: 1 * 60 * 1000,
    refetchOnWindowFocus: false,
    select: (responseData) => {
      // New envelope: { code, data: { data: [...], summary: { totalAmount, totalTransactions }, pagination: {...} } }
      const payload = responseData?.data;
      const transactionsRaw = Array.isArray(payload?.data)
        ? payload.data
        : Array.isArray(payload)
          ? payload
          : [];

      const normalized = transactionsRaw
        .map((tx, index) => {
          if (!tx) { return null; }

          const amount = parseAmount(tx.amount);
          const rawDate = tx.created_at || tx.date;
          const createdAt = rawDate ? new Date(rawDate) : null;
          const displayDate = createdAt && !Number.isNaN(createdAt.getTime())
            ? createdAt.toLocaleString('en-US', {
                month: 'short', day: 'numeric',
                hour: '2-digit', minute: '2-digit',
              })
            : '—';

          const rawStatus = (tx.status || 'unknown').toString().toLowerCase();
          const statusMapping = {
            paid: 'success', completed: 'success', succeeded: 'success',
            overdue: 'failed', rejected: 'failed', error: 'failed', cancelled: 'failed',
            sent: 'pending', processing: 'pending', draft: 'pending', unknown: 'pending',
            success: 'success', failed: 'failed', pending: 'pending',
          };
          const mappedStatus = statusMapping[rawStatus] || rawStatus;

          // Consumer endpoint: destination_name / destination_number are the payer fields
          const collectedFrom = tx.destination_name || tx.customer_name || tx.customerName
            || tx.deductedcustomername || tx.deducted_customer_name || '—';
          const collectedFromPhone = tx.destination_number || tx.customer_phone || tx.customerPhone
            || tx.deductedcustomerphonenumber || tx.deducted_customer_phone_number
            || tx.phone || '';

          return {
            id: tx.id || tx.reference || tx.customer_reference_id || `txn-${index}`,
            reference: tx.customer_reference_id || tx.reference || '—',
            collectedFrom,
            collectedFromPhone,
            narration: tx.narration || tx.description || '',
            collectionType: tx.collection_type || tx.service || '',
            channel: tx.channel || '',
            source: tx.source || '',
            reason: tx.asyncresponse_message || tx.syncresponse_message || tx.reason || '',
            amount,
            status: mappedStatus,
            dueDate: displayDate,
            date: createdAt,
          };
        })
        .filter(Boolean);

      // Use summary fields from the new envelope
      const apiSummary = payload?.summary || {};
      const successfulTransactions = normalized.filter(tx => tx.status === 'success');
      const totalAmount = parseAmount(apiSummary.totalAmount) || successfulTransactions.reduce((sum, tx) => sum + (tx.amount || 0), 0);
      const transactionCount = parseAmount(apiSummary.totalTransactions) || successfulTransactions.length;
      const averageAmount = transactionCount > 0 ? totalAmount / transactionCount : 0;
      const pendingAmount = normalized
        .filter(tx => tx.status === 'pending')
        .reduce((sum, tx) => sum + (tx.amount || 0), 0);

      const pagination = payload?.pagination || null;

      return {
        transactions: normalized,
        summary: { totalAmount, transactionCount, averageAmount, pendingAmount },
        pagination,
      };
    },
  });

  // Fetch dashboard metrics to get the global Total Collections value
  const { data: dashboardResponse, isLoading: isLoadingDashboard } = useQuery({
    queryKey: queryKeys.dashboard.metrics(),
    endpoint: '/auth/get-dashboard-metrics',
    staleTime: 1 * 60 * 1000,
    refetchOnWindowFocus: false,
    refetchOnMount: false,
  });

  const dashboardMetrics = dashboardResponse?.code === '00' ? dashboardResponse.data : null;
  const globalTotalCollections = parseAmount(dashboardMetrics?.total_collection);
  const globalWalletCurrency = dashboardMetrics?.wallet_currency || 'GHS';


  const invoices = reportData?.transactions || [];
  const summary = reportData?.summary || {
    totalAmount: 0,
    transactionCount: 0,
    averageAmount: 0,
  };

  const filteredInvoices = useMemo(() => {
    return invoices.filter(invoice => {
      const term = (debouncedSearchTerm || '').toLowerCase();
      const matchesSearch = !term ||
        invoice.collectedFrom?.toLowerCase().includes(term) ||
        invoice.collectedFromPhone?.toLowerCase().includes(term) ||
        invoice.reference?.toLowerCase().includes(term) ||
        invoice.narration?.toLowerCase().includes(term) ||
        invoice.collectionType?.toLowerCase().includes(term) ||
        invoice.channel?.toLowerCase().includes(term) ||
        invoice.source?.toLowerCase().includes(term) ||
        invoice.reason?.toLowerCase().includes(term) ||
        invoice.amount?.toString().includes(term) ||
        invoice.status?.toLowerCase().includes(term);

      const matchesStatus = statusFilter === 'all' || invoice.status === statusFilter;

      return matchesSearch && matchesStatus;
    });
  }, [invoices, debouncedSearchTerm, statusFilter]);

  const totalPages = Math.ceil(filteredInvoices.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentInvoices = filteredInvoices.slice(startIndex, endIndex);

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter]);

  const handlePageChange = useCallback((page) => {
    setCurrentPage(page);
  }, []);

  const handleCreateInvoice = useCallback(() => {
    if (isPageLoading) { return; }
    navigate('/invoicing');
  }, [isPageLoading, navigate]);

  const handleAddMoney = useCallback(() => {
    if (isPageLoading) { return; }
    logger.debug('Opening Add Money Modal');
    setShowAddMoneyModal(true);
  }, [isPageLoading]);

  const handleCloseModal = useCallback(() => {
    setShowAddMoneyModal(false);
  }, []);

  const handleGenerateCheckout = useCallback(() => {
    if (isPageLoading) { return; }
    logger.debug('Opening Generate Checkout Modal');
    setShowGenerateCheckoutModal(true);
  }, [isPageLoading]);

  const handleCloseGenerateCheckoutModal = useCallback(() => {
    setShowGenerateCheckoutModal(false);
  }, []);


  const getStatusChip = (status) => {
    // Status is already normalized during data fetching
    const normalizedStatus = (status || '').toLowerCase();

    // Only support success, pending, and failed statuses
    const statusConfig = {
      success: { class: 'paid', label: t('success', { ns: 'collections', defaultValue: 'Success' }) },
      failed: { class: 'overdue', label: t('failed', { ns: 'collections', defaultValue: 'Failed' }) },
      pending: { class: 'sent', label: t('pending', { ns: 'collections', defaultValue: 'Pending' }) }
    };

    const config = statusConfig[normalizedStatus] || statusConfig.pending;

    return <span className={`chip ${config.class}`}>{config.label}</span>;
  };



  return (
    <div style={{ transition: 'opacity 0.2s ease' }}>
      <section className="metrics-grid">
        {[
          {
            title: t('totalCollections', { ns: 'collections' }),
            value: formatCurrencyAmount(globalTotalCollections || summary.totalAmount, globalWalletCurrency),
            hint: null,
            icon: 'paid',
            trend: 'flat',
            trendBadge: null,
            accent: '#0ea5e9',
          },
          {
            title: t('collectionRate', { ns: 'collections' }),
            value: summary.transactionCount > 0
              ? formatCurrencyAmount(summary.averageAmount, 'GHS')
              : formatCurrencyAmount(0, 'GHS'),
            hint: t('averageTransaction', { ns: 'collections', defaultValue: 'Average per transaction' }),
            icon: 'trending_up',
            trend: 'flat',
            trendBadge: null,
            accent: '#22c55e',
          },
          {
            title: t('pendingAmount', { ns: 'collections' }),
            value: formatCurrencyAmount(
              reportData?.summary?.pendingAmount ||
              invoices.filter(inv => inv.status === 'pending').reduce((sum, inv) => sum + inv.amount, 0),
              'GHS'
            ),
            hint: t('awaitingPayment', { ns: 'collections' }),
            icon: 'hourglass_empty',
            trend: 'flat',
            trendBadge: null,
            accent: '#f97316',
          },
        ].map((metric) => (
          <MetricCard
            key={metric.title}
            title={metric.title}
            value={metric.value}
            hint={metric.hint}
            icon={metric.icon}
            trend={metric.trend}
            trendBadge={metric.trendBadge}
            accent={metric.accent}
            accentSoft={withAlpha(metric.accent, 0.16)}
            accentStrong={withAlpha(metric.accent, 0.34)}
            className="metric-card--compact"
          />
        ))}
      </section>

      {/* Top Action Buttons - Responsive CSS Classes */}
      <div className="collections-actions-group" style={{
        display: 'flex',
        gap: '12px',
        marginBottom: '24px',
        flexWrap: 'wrap'
      }}>
        <button
          type="button"
          className="btn primary collections-action-btn"
          onClick={handleCreateInvoice}
          disabled={isPageLoading}
          style={{
            padding: '12px 24px',
            fontSize: '14px',
            cursor: isPageLoading ? 'not-allowed' : 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
            backgroundColor: isPageLoading ? 'var(--border-primary)' : 'var(--accent)',
            color: 'var(--text-inverse)',
            border: 'none',
            borderRadius: '10px',
            fontWeight: '600',
            transition: 'all 0.2s ease',
            minWidth: '160px',
            opacity: isPageLoading ? 0.6 : 1
          }}
        >
          <span className="material-symbols-outlined">add_notes</span>
          {t('createInvoice', { ns: 'collections' })}
        </button>

        <button
          type="button"
          className="btn primary collections-action-btn"
          onClick={handleAddMoney}
          disabled={isPageLoading}
          style={{
            padding: '12px 24px',
            fontSize: '14px',
            cursor: isPageLoading ? 'not-allowed' : 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
            backgroundColor: isPageLoading ? 'var(--border-primary)' : 'var(--accent)',
            color: 'var(--text-inverse)',
            border: 'none',
            borderRadius: '10px',
            fontWeight: '600',
            transition: 'all 0.2s ease',
            minWidth: '160px',
            opacity: isPageLoading ? 0.6 : 1
          }}
        >
          <span className="material-symbols-outlined">account_balance_wallet</span>
          {t('addMoneyToWallet', { ns: 'dashboard', defaultValue: 'Add Money to Wallet' })}
        </button>

        {!isAgent && (
          <button
            type="button"
            className="btn primary collections-action-btn"
            onClick={handleGenerateCheckout}
            disabled={isPageLoading}
            style={{
              padding: '12px 24px',
              fontSize: '14px',
              cursor: isPageLoading ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px',
              backgroundColor: isPageLoading ? 'var(--border-primary)' : 'var(--accent)',
              color: 'var(--text-inverse)',
              border: 'none',
              borderRadius: '10px',
              fontWeight: '600',
              transition: 'all 0.2s ease',
              minWidth: '160px',
              opacity: isPageLoading ? 0.6 : 1
            }}
          >
            <span className="material-symbols-outlined">receipt_long</span>
            {t('generateCheckout', { ns: 'dashboard', defaultValue: 'Generate Checkout' })}
          </button>
        )}

      </div>

      <div className="content-row" style={{ gridTemplateColumns: '1fr', marginTop: '0' }}>
        <div className="invoices-card" style={{ width: '100%', marginLeft: '0', minHeight: '450px' }} data-tour="collections-list">
          <div className="card-head" data-tour="collections-header">
            <h3>{t('invoiceManagement', { ns: 'collections' })}</h3>
            <div className="head-actions" data-tour="collections-filters">
              <select
                className="filter"
                value={statusFilter}
                onChange={(e) => {
                  setStatusFilter(e.target.value);
                  setCurrentPage(1); // Reset to first page when filter changes
                }}
              >
                <option value="all">{t('allStatus', { ns: 'collections' })}</option>
                <option value="success">{t('success', { ns: 'collections', defaultValue: 'Success' })}</option>
                <option value="pending">{t('pending', { ns: 'collections', defaultValue: 'Pending' })}</option>
                <option value="failed">{t('failed', { ns: 'collections', defaultValue: 'Failed' })}</option>
              </select>
              <input
                type="text"
                className="small-search"
                placeholder={t('searchInvoices', { ns: 'collections' })}
                value={searchTerm}
                onChange={(e) => updateSearch(e.target.value)}
              />
            </div>
          </div>

          {isLoading ? (
            <div style={{
              padding: '48px 24px',
              textAlign: 'center',
              color: 'var(--text-muted)'
            }}>
              <LoadingSpinner size="large" />
              <p style={{ fontSize: '16px', margin: '16px 0 0 0' }}>
                {t('loading', { ns: 'common', defaultValue: 'Loading...' })}
              </p>
            </div>
          ) : loadError ? (
            <div style={{
              padding: '48px 24px',
              textAlign: 'center',
              color: 'var(--error)'
            }}>
              <span className="material-symbols-outlined" style={{
                fontSize: '48px',
                marginBottom: '16px',
                display: 'block',
                opacity: 0.5
              }}>
                error
              </span>
              <p style={{ fontSize: '16px', margin: 0 }}>
                {loadError instanceof Error ? loadError.message : String(loadError)}
              </p>
            </div>
          ) : filteredInvoices.length === 0 ? (
            <div style={{
              padding: '48px 24px',
              textAlign: 'center',
              color: 'var(--text-muted)'
            }}>
              <span className="material-symbols-outlined" style={{
                fontSize: '48px',
                marginBottom: '16px',
                display: 'block',
                opacity: 0.5
              }}>
                description
              </span>
              <p style={{ fontSize: '16px', margin: 0 }}>
                {t('noInvoices', { ns: 'collections', defaultValue: 'No collections found' })}
              </p>
              <p style={{ fontSize: '14px', margin: '8px 0 0 0', opacity: 0.7 }}>
                {t('createFirstInvoice', { ns: 'collections', defaultValue: 'No collection transactions in the selected period' })}
              </p>
            </div>
          ) : (
            <table className="invoices-table" key={`page-${currentPage}`} data-tour="collections-table">
              <thead>
                <tr>
                  <th>{t('reference', { ns: 'collections', defaultValue: 'Reference' })}</th>
                  <th>{t('collectedFrom', { ns: 'collections', defaultValue: 'Collected From' })}</th>
                  <th>{t('collectionType', { ns: 'collections', defaultValue: 'Type' })}</th>
                  <th>{t('narration', { ns: 'collections', defaultValue: 'Narration' })}</th>
                  <th>{t('amount', { ns: 'collections' })}</th>
                  <th>{t('status', { ns: 'collections' })}</th>
                  <th>{t('date', { ns: 'collections', defaultValue: 'Date' })}</th>
                </tr>
              </thead>
              <tbody>
                {currentInvoices.map((invoice, index) => (
                  <tr
                    key={invoice.id || `invoice-${index}`}
                    onClick={() => setSelectedTransaction(invoice)}
                    style={{ cursor: 'pointer' }}
                  >

                    {/* Reference */}
                    <td className="table-strong" data-label={t('reference', { ns: 'collections', defaultValue: 'Reference' })}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="tx-flow-icon tx-flow-icon--in tx-flow-icon--sm" title="Money In" aria-label="Money In">
                          <FaArrowDown aria-hidden="true" />
                        </span>
                        <span style={{ fontSize: '0.875rem', fontWeight: '500' }}>
                          {invoice.reference}
                        </span>
                      </div>
                    </td>

                    {/* Collected From */}
                    <td data-label={t('collectedFrom', { ns: 'collections', defaultValue: 'Collected From' })}>
                      <div style={{ fontSize: '0.875rem', fontWeight: '500', color: 'var(--text-primary)' }}>
                        {invoice.collectedFrom}
                      </div>
                      {invoice.collectedFromPhone && (
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '2px' }}>
                          {invoice.collectedFromPhone}
                        </div>
                      )}
                    </td>

                    {/* Type + Channel */}
                    <td data-label={t('collectionType', { ns: 'collections', defaultValue: 'Type' })}>
                      {invoice.collectionType ? (
                        <span style={{
                          display: 'inline-block',
                          padding: '2px 8px',
                          borderRadius: '4px',
                          fontSize: '0.75rem',
                          fontWeight: '600',
                          background: 'var(--success-bg)',
                          color: 'var(--success)',
                          textTransform: 'capitalize',
                        }}>
                          {invoice.collectionType.replace(/[_-]+/g, ' ')}
                        </span>
                      ) : <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>—</span>}
                      {invoice.channel && (
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '3px', textTransform: 'capitalize' }}>
                          {invoice.channel.replace(/[_-]+/g, ' ')}
                        </div>
                      )}
                    </td>

                    {/* Narration */}
                    <td data-label={t('narration', { ns: 'collections', defaultValue: 'Narration' })}>
                      <div style={{
                        fontSize: '0.875rem',
                        color: 'var(--text-primary)',
                        maxWidth: '160px',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                      }}
                        title={invoice.narration}
                      >
                        {invoice.narration || <span style={{ color: 'var(--text-muted)' }}>—</span>}
                      </div>
                    </td>

                    {/* Amount */}
                    <td className="table-amount" data-label={t('amount', { ns: 'collections' })}>
                      <span style={{ fontSize: '0.875rem', fontWeight: '600' }}>
                        {formatCurrencyAmount(invoice.amount, 'GHS')}
                      </span>
                    </td>

                    {/* Status + Reason */}
                    <td data-label={t('status', { ns: 'collections' })}>
                      {getStatusChip(invoice.status)}
                      {invoice.reason && (
                        <div style={{
                          fontSize: '0.75rem',
                          color: 'var(--text-muted)',
                          marginTop: '3px',
                          maxWidth: '120px',
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          textTransform: 'capitalize',
                        }} title={invoice.reason}>
                          {invoice.reason}
                        </div>
                      )}
                    </td>

                    {/* Date */}
                    <td data-label={t('date', { ns: 'collections', defaultValue: 'Date' })}>
                      <span style={{ fontSize: '0.875rem', color: 'var(--text-primary)' }}>
                        {invoice.dueDate}
                      </span>
                    </td>

                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {/* Pagination Component */}
          {filteredInvoices.length > 0 && (
            <Pagination
              currentPage={currentPage}
              totalItems={filteredInvoices.length}
              itemsPerPage={itemsPerPage}
              onPageChange={handlePageChange}
              showInfo={true}
            />
          )}
        </div>
      </div>

      {/* Transaction Detail Modal */}
      {selectedTransaction && (
        <div
          onClick={() => setSelectedTransaction(null)}
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(0,0,0,0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
            padding: '16px',
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              backgroundColor: 'var(--card)',
              borderRadius: '16px',
              padding: '28px',
              width: '100%',
              maxWidth: '480px',
              boxShadow: 'var(--shadow-xl)',
              maxHeight: '90vh',
              overflowY: 'auto',
            }}
          >
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '20px' }}>
              <div>
                <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: '700', color: 'var(--text-primary)' }}>
                  Transaction Details
                </h3>
                <p style={{ margin: '4px 0 0', fontSize: '0.8rem', color: 'var(--text-muted)', fontFamily: 'monospace' }}>
                  {selectedTransaction.reference}
                </p>
              </div>
              <button
                onClick={() => setSelectedTransaction(null)}
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  color: 'var(--text-muted)',
                  padding: '4px',
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: '22px' }}>close</span>
              </button>
            </div>

            {/* Amount hero */}
            <div style={{
              textAlign: 'center',
              padding: '20px',
              background: 'var(--success-bg)',
              borderRadius: '12px',
              marginBottom: '20px',
            }}>
              <div style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--success)' }}>
                {formatCurrencyAmount(selectedTransaction.amount, 'GHS')}
              </div>
              <div style={{ marginTop: '8px' }}>
                {getStatusChip(selectedTransaction.status)}
              </div>
              {selectedTransaction.reason && (
                <div style={{
                  marginTop: '8px',
                  fontSize: '0.8rem',
                  color: 'var(--text-muted)',
                  textTransform: 'capitalize',
                }}>
                  {selectedTransaction.reason}
                </div>
              )}
            </div>

            {/* Detail rows */}
            {[
              { label: 'Collected From', value: selectedTransaction.collectedFrom },
              { label: 'Phone', value: selectedTransaction.collectedFromPhone },
              { label: 'Collection Type', value: selectedTransaction.collectionType?.replace(/[_-]+/g, ' ') },
              { label: 'Channel', value: selectedTransaction.channel?.replace(/[_-]+/g, ' ') },
              { label: 'Narration', value: selectedTransaction.narration },
              { label: 'Date', value: selectedTransaction.dueDate },
            ].filter(row => row.value).map(row => (
              <div key={row.label} style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'flex-start',
                padding: '12px 0',
                borderBottom: '1px solid var(--border-primary)',
                gap: '16px',
              }}>
                <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', flexShrink: 0, textTransform: 'capitalize' }}>
                  {row.label}
                </span>
                <span style={{
                  fontSize: '0.875rem',
                  fontWeight: '500',
                  color: 'var(--text-primary)',
                  textAlign: 'right',
                  textTransform: 'capitalize',
                  wordBreak: 'break-word',
                }}>
                  {row.value}
                </span>
              </div>
            ))}

            <button
              onClick={() => setSelectedTransaction(null)}
              style={{
                marginTop: '20px',
                width: '100%',
                padding: '12px',
                borderRadius: '10px',
                border: 'none',
                background: 'var(--accent)',
                color: 'var(--text-inverse)',
                fontWeight: '600',
                fontSize: '0.9rem',
                cursor: 'pointer',
              }}
            >
              Close
            </button>
          </div>
        </div>
      )}

      <AddMoneyToWalletModal
        isOpen={showAddMoneyModal}
        onClose={handleCloseModal}
      />

      <GenerateCheckoutLinkModal
        isOpen={showGenerateCheckoutModal}
        onClose={handleCloseGenerateCheckoutModal}
      />

    </div>
  );
};

export default Collections;